func solve(n int64, edges [][]int64, k int64) int64 {
	// Sort edges by time in ascending order
	sort.Slice(edges, func(i, j int) bool {
		return edges[i][2] < edges[j][2]
	})

	// Initialize Union-Find structure
	uf := &UnionFind{
		parent: make([]int64, n),
	}
	for i := int64(0); i < n; i++ {
		uf.parent[i] = i
	}

	// Keep track of the number of connected components
	componentCount := n

	// Use a min-heap to process edges in order of their removal time
	// We'll reverse the edges to simulate adding edges in reverse order (i.e., removing edges in original order)
	// So we'll use a max-heap to process edges in reverse order
	type EdgeHeap struct {
		edges []Edge
	}
	heap := &EdgeHeap{
		edges: edges,
	}
	heapify(heap)

	// We'll use a variable to track the answer
	var answer int64 = 0

	// Process edges in reverse order (i.e., remove edges in original order)
	for heap.Len() > 0 {
		// Get the edge with the largest time (i.e., the one that will be removed last)
		edge := heap.Pop().(Edge)
		// Remove the edge from the graph
		uf.Union(edge.u, edge.v)
		// Check if the number of connected components is at least k
		if componentCount >= k {
			// If so, this is the answer
			answer = edge.time
			break
		}
		// Decrease the component count if the edge was connecting two separate components
		if uf.Find(edge.u) != uf.Find(edge.v) {
			componentCount--
		}
	}

	return answer
}

func heapify(h *EdgeHeap) {
	for i := h.Len() / 2 - 1; i >= 0; i-- {
		h.siftDown(i)
	}
}

func (h *EdgeHeap) Len() int {
	return len(h.edges)
}

func (h *EdgeHeap) Pop() interface{} {
	if h.Len() == 0 {
		return nil
	}
	// Swap the last element with the first
	last := h.edges[h.Len()-1]
	h.edges[h.Len()-1] = h.edges[0]
	h.edges[0] = last
	h.Len--
	h.siftDown(0)
	return h.edges[0]
}

func (h *EdgeHeap) siftDown(i int) {
	for i < h.Len() {
		left := 2*i + 1
		right := 2*i + 2
		smallest := i
		if left < h.Len() && h.edges[left].time > h.edges[smallest].time {
			smallest = left
		}
		if right < h.Len() && h.edges[right].time > h.edges[smallest].time {
			smallest = right
		}
		if smallest != i {
			h.edges[i], h.edges[smallest] = h.edges[smallest], h.edges[i]
			i = smallest
		} else {
			break
		}
	}
}
