	n := len(old)
	*h = old[0 : n-1]
	return old[n-1]
}

func solve(n int64, edges [][]int64, k int64) int64 {
	if k == 1 {
		return 0
	}

	// Sort edges by time to process them in increasing order
	sort.Slice(edges, func(i, j int) bool {
		return edges[i][2] < edges[j][2]
	})

	// Initialize DSU (Disjoint Set Union) structure
	parent := make([]int64, n)
	rank := make([]int64, n)

	for i := range parent {
		parent[i] = i
		rank[i] = 1
	}

	// Function to find the root of a node
	find := func(x int64) int64 {
		if parent[x] != x {
			parent[x] = find(parent[x])
		}
		return parent[x]
	}

	// Function to union two nodes
	union := func(x, y int64) {
		xRoot := find(x)
		yRoot := find(y)
		if xRoot == yRoot {
			return
		}
		if rank[xRoot] < rank[yRoot] {
